// Парсим сообщение от пользователя Telegram. Поддерживаем 2 формата:
// 1) Свободный текст — берём как описание (Имя=ник, Телефон=username)
// 2) Структурированный (предпочтительно):
//    Имя: Иван Петров
//    Телефон: +79991234567
//    Email: ivan@test.ru
//    Компания: ООО Альфа
//    Тема: АКЗ резервуара
//    Описание: 200 м²

const msg = $input.first().json.message || {};
const text = (msg.text || '').trim();
const from = msg.from || {};

// Имя из Telegram-профиля как fallback
const tgName = [from.first_name, from.last_name].filter(Boolean).join(' ') || from.username || 'Не указан';

// Парсим структуру «Поле: значение»
const fields = {
  name: tgName,
  phone: '',
  email: '',
  company: '',
  subject: '',
  description: text,
};

const patterns = {
  name: /(?:имя|name)\s*[:\-]\s*(.+)/i,
  phone: /(?:телефон|тел|phone)\s*[:\-]\s*(.+)/i,
  email: /(?:email|почта|mail)\s*[:\-]\s*(.+)/i,
  company: /(?:компания|организация|company|фирма)\s*[:\-]\s*(.+)/i,
  subject: /(?:тема|объект|subject|работа)\s*[:\-]\s*(.+)/i,
  description: /(?:описание|задача|description|details)\s*[:\-]\s*(.+)/i,
};

let structured = false;
for (const [key, re] of Object.entries(patterns)) {
  const m = text.match(re);
  if (m) {
    fields[key] = m[1].split('\n')[0].trim();
    structured = true;
  }
}

// Если не структурированное и нет телефона → запросим у юзера
if (!structured && !fields.phone && from.id) {
  // Берём из контакта Telegram если шарил, иначе пометим запрос
  fields._needs_contact = !msg.contact;
}

// Если шарил контакт — берём оттуда
if (msg.contact) {
  fields.phone = msg.contact.phone_number || '';
  fields.name = `${msg.contact.first_name || ''} ${msg.contact.last_name || ''}`.trim() || fields.name;
}

fields.source = 'Telegram';
fields.tg_user_id = String(from.id || '');
fields.tg_username = from.username || '';
fields.chat_id = String(msg.chat?.id || from.id || '');

return [{ json: fields }];
